'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './badge.module.css'

export interface BadgeProps extends HTMLAttributes<HTMLSpanElement> {
  variant?: 'default' | 'secondary' | 'success' | 'warning' | 'destructive' | 'outline'
  size?: 'sm' | 'md'
}

export function Badge({
  variant = 'default',
  size = 'md',
  className,
  children,
  ...props
}: BadgeProps) {
  return (
    <span
      data-variant={variant}
      data-size={size}
      className={cn(styles['badge'], className)}
      {...props}
    >
      {children}
    </span>
  )
}

@layer cascivo.component {
  .badge {
    display: inline-flex;
    align-items: center;
    font-family: var(--cascivo-font-sans);
    font-weight: var(--cascivo-font-medium);
    border-radius: var(--cascivo-radius-badge);
    border: 1px solid transparent;
    white-space: nowrap;

    &[data-size='sm'] {
      padding-inline: var(--cascivo-space-2);
      padding-block: var(--cascivo-space-1);
      font-size: var(--cascivo-text-xs);
      line-height: 1;
    }

    &[data-size='md'] {
      padding-inline: var(--cascivo-space-3);
      padding-block: var(--cascivo-space-1);
      font-size: var(--cascivo-text-xs);
      line-height: var(--cascivo-leading-normal);
    }

    &[data-variant='default'] {
      background-color: var(--cascivo-color-accent);
      color: var(--cascivo-color-text-on-accent);
    }

    &[data-variant='secondary'] {
      background-color: var(--cascivo-color-bg-subtle);
      color: var(--cascivo-color-text);
      border-color: var(--cascivo-color-border);
    }

    &[data-variant='success'] {
      background-color: var(--cascivo-color-success-subtle);
      color: var(--cascivo-color-success-foreground);
    }

    &[data-variant='warning'] {
      background-color: var(--cascivo-color-warning-subtle);
      color: var(--cascivo-color-warning-foreground);
    }

    &[data-variant='destructive'] {
      background-color: var(--cascivo-color-destructive-subtle);
      color: var(--cascivo-color-destructive-foreground);
    }

    &[data-variant='primary'] {
      background-color: var(--cascivo-color-primary);
      color: var(--cascivo-color-primary-content);
    }

    &[data-variant='info'] {
      background-color: var(--cascivo-color-info);
      color: var(--cascivo-color-info-content);
    }

    &[data-variant='error'] {
      background-color: var(--cascivo-color-error);
      color: var(--cascivo-color-error-content);
    }

    &[data-variant='outline'] {
      background-color: transparent;
      color: var(--cascivo-color-text);
      border-color: var(--cascivo-color-border-strong);
    }
  }
}

@media (forced-colors: active) {
  .badge {
    border: 1px solid CanvasText;
    color: CanvasText;
  }
}

@media (prefers-contrast: more) {
  .badge {
    border-width: 2px;
  }
}
